  class StackNode
  {
    public state: number;
    private code: number;
    public pos: number;
    public link: StackNode | null;

    constructor(state: number, code: number, pos: number, link: StackNode | null)
    {
      this.state = state;
      this.code = code;
      this.pos = pos;
      this.link = link;
    }

    equals(obj: StackNode)
    {
      var lhs: StackNode | null = this;
      var rhs: StackNode | null = obj;
      while (lhs != null && rhs != null)
      {
        if (lhs == rhs) return true;
        if (lhs.state != rhs.state) return false;
        if (lhs.code != rhs.code) return false;
        if (lhs.pos != rhs.pos) return false;
        lhs = lhs.link;
        rhs = rhs.link;
      }
      return lhs == rhs;
    }

    private lookback(x: number, y: number)
    {
      var i = Parser.LOOKBACK[y];
      var l = Parser.LOOKBACK[i];
      while (l > x)
      {
        i += 2;
        l = Parser.LOOKBACK[i];
      }
      if (l < x)
      {
        return 0;
      }
      else
      {
        return Parser.LOOKBACK[i + 1];
      }
    }

    public count(code: number)

    {
      var count = 0;
      for (var node: StackNode | null = this; node!.state >= 0; node = node!.link)
      {
        code = this.lookback(node!.code, code);
        if (code == 0)
        {
          break;
        }
        count += 1;
      }
      return count;
    }

  }

  class DeferredEvent
  {
    private link: DeferredEvent | null;
    private name: string;
    private begin: number;
    private end: number;
    private count: number;

    constructor(link: DeferredEvent | null, name: string, begin: number, end: number, count: number)
    {
      this.link = link;
      this.name = name;
      this.link = link;
      this.begin = begin;
      this.end = end;
      this.count = count;
    }

    execute(eventHandler: BottomUpEventHandler)
    {
      if (this.count < 0)
      {
        eventHandler.terminal(this.name, this.begin, this.end);
      }
      else
      {
        eventHandler.nonterminal(this.name, this.begin, this.end, this.count);
      }
    }

    release(eventHandler: BottomUpEventHandler)
    {
      var current: DeferredEvent | null = this;
      var predecessor = current.link;
      current.link = null;
      while (predecessor != null)
      {
        var next = predecessor.link;
        predecessor.link = current;
        current = predecessor;
        predecessor = next;
      }
      do
      {
        current.execute(eventHandler);
        current = current.link;
      }
      while (current != null);
    }

    show(eventHandler: BottomUpEventHandler)
    {
      var stack = [];
      for (var current: DeferredEvent | null = this; current != null; current = current.link)
      {
        stack.push(current);
      }
      while (stack.length > 0)
      {
        stack.pop()!.execute(eventHandler);
      }
    }
  }

  class Heap
  {
    private array: ParsingThread[] = [];
    private size = 0;

    constructor() {}

    offer(value: ParsingThread)
    {
      var index = this.size++;
      while (index != 0)
      {
        var parentIndex = (index - 1) >> 1;
        if (this.array[parentIndex].compareTo(value) <= 0)
          break;
        this.array[index] = this.array[parentIndex];
        index = parentIndex;
      }
      this.array[index] = value;
    }

    poll()
    {
      var min = this.array[0];
      if (--this.size > 0)
      {
        var value = this.array[this.size];
        var index = 0;
        for (var child;;)
        {
          child = (index << 1) + 2;
          if (child < this.size)
          {
            var otherChild = child - 1;
            if (otherChild < this.size && this.array[child].compareTo(this.array[otherChild]) > 0)
              child = otherChild;
          }
          else if (--child >= this.size)
          {
            break;
          }
          if (value.compareTo(this.array[child]) <= 0)
          {
            break;
          }
          this.array[index] = this.array[child];
          index = child;
        }
        this.array[index] = value;
      }
      return min;
    }

    peek()
    {
      return this.array[0];
    }

    isEmpty(): boolean
    {
      return this.size == 0;
    }
  }

